import { useState } from "react";
import { saveVitals } from "../services/api";
import { useNavigate } from "react-router-dom";

function Vitals() {
  const userId = localStorage.getItem("user_id");
  const navigate = useNavigate();

  const [age, setAge] = useState("");
  const [glucose, setGlucose] = useState("");
  const [height, setHeight] = useState("");
  const [weight, setWeight] = useState("");
  const [bp, setBp] = useState("");

  // BMI calculation
  const bmi = height && weight
    ? (weight / ((height / 100) ** 2)).toFixed(2)
    : "";

  const handleSave = async () => {
    try {
      await saveVitals({
        user_id: userId,
        age,
        glucose,
        bmi,
        bp
      });
      alert("Vitals saved successfully");
      navigate("/consult");
    } catch (err) {
      alert("Failed to save vitals");
      console.error(err);
    }
  };

  return (
    <div>
      <h2>Enter Vitals</h2>

      <input placeholder="Age" value={age} onChange={e => setAge(e.target.value)} />
      <br />

      <input placeholder="Glucose Level (mg/dL)" value={glucose} onChange={e => setGlucose(e.target.value)} />
      <br />

      <input placeholder="Height (cm)" value={height} onChange={e => setHeight(e.target.value)} />
      <br />

      <input placeholder="Weight (kg)" value={weight} onChange={e => setWeight(e.target.value)} />
      <br />

      <input placeholder="Blood Pressure" value={bp} onChange={e => setBp(e.target.value)} />
      <br />

      <p><b>Calculated BMI:</b> {bmi}</p>

      <button onClick={handleSave}>Save Vitals</button>
    </div>
  );
}

export default Vitals;
